// Admin.js - Redesigned
import React, { useState, useEffect } from 'react';
import { Link, useSearchParams } from 'react-router-dom';
import { motion, AnimatePresence } from 'framer-motion';

const API = '';

export default function Admin() {
  const [projects, setProjects] = useState([]);
  const [searchParams, setSearchParams] = useSearchParams();
  const [alertMsg, setAlertMsg] = useState('');
  const [isSidebarOpen, setIsSidebarOpen] = useState(true);

  useEffect(() => {
    const status = searchParams.get('status');
    if (status === 'tambah') setAlertMsg('Project successfully added!');
    else if (status === 'edit') setAlertMsg('Project successfully updated!');
    else if (status === 'hapus') setAlertMsg('Project successfully deleted!');
  }, [searchParams]);

  useEffect(() => {
    fetch(`${API}/api/projects`).then(r => r.json()).then(setProjects).catch(console.error);
  }, []);

  const handleHapus = (id) => {
    if (!window.confirm('Are you sure you want to delete this project?')) return;
    fetch(`${API}/api/projects/${id}`, { method: 'DELETE' })
      .then(r => r.json())
      .then(() => {
        setProjects(prev => prev.filter(p => p.id !== id));
        setAlertMsg('Project successfully deleted!');
        setSearchParams({ status: 'hapus' });
      })
      .catch(console.error);
  };

  return (
    <>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Space+Grotesk:wght@400;500;600;700;800;900&family=Inter:wght@300;400;500;600;700&family=IBM+Plex+Mono:wght@400;500;600&display=swap');

        * { margin: 0; padding: 0; box-sizing: border-box; }

        body {
          background: #090909;
          color: #F5F5F5;
          font-family: 'Inter', -apple-system, BlinkMacSystemFont, sans-serif;
          min-height: 100vh;
          overflow-x: hidden;
        }

        body::before {
          content: '';
          position: fixed;
          inset: 0;
          z-index: 0;
          pointer-events: none;
          background-image: 
            radial-gradient(circle at 20% 30%, rgba(255,62,165,0.03) 0%, transparent 50%),
            radial-gradient(circle at 80% 70%, rgba(216,167,177,0.03) 0%, transparent 50%);
        }

        .admin-layout {
          display: flex;
          min-height: 100vh;
          position: relative;
          z-index: 1;
        }

        /* Sidebar */
        .admin-sidebar {
          width: 260px;
          min-height: 100vh;
          background: rgba(20,20,20,0.95);
          border-right: 1px solid rgba(255,255,255,0.04);
          padding: 32px 20px;
          position: sticky;
          top: 0;
          height: 100vh;
          overflow-y: auto;
          flex-shrink: 0;
          transition: all 0.3s ease;
        }

        .admin-sidebar.collapsed {
          width: 0;
          padding: 0;
          overflow: hidden;
          border-right: none;
        }

        .sidebar-brand {
          font-family: 'Space Grotesk', sans-serif;
          font-weight: 900;
          font-size: 1.4rem;
          letter-spacing: -0.5px;
          padding-bottom: 24px;
          border-bottom: 1px solid rgba(255,255,255,0.04);
          margin-bottom: 24px;
        }

        .sidebar-brand .highlight {
          background: linear-gradient(135deg, #FF3EA5, #FF7CC7);
          -webkit-background-clip: text;
          -webkit-text-fill-color: transparent;
          background-clip: text;
        }

        .sidebar-nav {
          display: flex;
          flex-direction: column;
          gap: 4px;
        }

        .sidebar-nav .nav-item {
          display: flex;
          align-items: center;
          gap: 12px;
          padding: 12px 16px;
          border-radius: 12px;
          color: rgba(255,255,255,0.3);
          text-decoration: none;
          font-family: 'Inter', sans-serif;
          font-size: 0.85rem;
          font-weight: 500;
          transition: all 0.3s ease;
        }

        .sidebar-nav .nav-item:hover {
          background: rgba(255,255,255,0.03);
          color: rgba(255,255,255,0.6);
        }

        .sidebar-nav .nav-item.active {
          background: rgba(255,62,165,0.08);
          color: #FF7CC7;
          border: 1px solid rgba(255,62,165,0.08);
        }

        .sidebar-nav .nav-item i {
          width: 20px;
          text-align: center;
          font-size: 1rem;
        }

        .sidebar-toggle {
          display: none;
          position: fixed;
          bottom: 24px;
          right: 24px;
          z-index: 100;
          width: 48px;
          height: 48px;
          border-radius: 50%;
          border: 1px solid rgba(255,255,255,0.06);
          background: rgba(20,20,20,0.95);
          color: #F5F5F5;
          font-size: 1.2rem;
          cursor: pointer;
          transition: all 0.3s ease;
          backdrop-filter: blur(12px);
        }

        .sidebar-toggle:hover {
          border-color: rgba(255,62,165,0.15);
          color: #FF7CC7;
        }

        /* Main Content */
        .admin-main {
          flex: 1;
          padding: 32px 40px;
          max-width: calc(100% - 260px);
        }

        .admin-main.expanded {
          max-width: 100%;
        }

        .admin-header {
          display: flex;
          justify-content: space-between;
          align-items: center;
          flex-wrap: wrap;
          gap: 16px;
          margin-bottom: 32px;
        }

        .admin-title {
          font-family: 'Space Grotesk', sans-serif;
          font-weight: 800;
          font-size: 1.8rem;
          letter-spacing: -0.5px;
          color: #F5F5F5;
        }

        .admin-title .highlight {
          background: linear-gradient(135deg, #FF3EA5, #FF7CC7);
          -webkit-background-clip: text;
          -webkit-text-fill-color: transparent;
          background-clip: text;
        }

        .admin-badge {
          display: inline-flex;
          align-items: center;
          gap: 6px;
          padding: 6px 16px;
          border-radius: 100px;
          background: rgba(255,62,165,0.08);
          border: 1px solid rgba(255,62,165,0.08);
          color: #FF7CC7;
          font-size: 0.75rem;
          font-weight: 500;
        }

        .btn-primary-admin {
          display: inline-flex;
          align-items: center;
          gap: 8px;
          padding: 12px 24px;
          border-radius: 100px;
          background: rgba(255,62,165,0.12);
          border: 1px solid rgba(255,62,165,0.12);
          color: #FF7CC7;
          font-family: 'Inter', sans-serif;
          font-weight: 600;
          font-size: 0.85rem;
          text-decoration: none;
          transition: all 0.3s ease;
        }

        .btn-primary-admin:hover {
          background: rgba(255,62,165,0.2);
          border-color: rgba(255,62,165,0.2);
          transform: translateY(-2px);
          color: #FF7CC7;
        }

        .alert-glass {
          padding: 16px 20px;
          border-radius: 16px;
          background: rgba(255,255,255,0.02);
          border: 1px solid rgba(255,255,255,0.04);
          margin-bottom: 24px;
          display: flex;
          align-items: center;
          justify-content: space-between;
        }

        .alert-glass .alert-content {
          display: flex;
          align-items: center;
          gap: 12px;
          color: rgba(255,255,255,0.6);
          font-size: 0.9rem;
        }

        .alert-glass .alert-content i {
          color: #FF7CC7;
        }

        .alert-close {
          background: none;
          border: none;
          color: rgba(255,255,255,0.2);
          font-size: 1.2rem;
          cursor: pointer;
          transition: all 0.3s ease;
        }

        .alert-close:hover {
          color: rgba(255,255,255,0.5);
        }

        /* Table */
        .table-container {
          border-radius: 20px;
          border: 1px solid rgba(255,255,255,0.04);
          overflow: hidden;
          background: rgba(255,255,255,0.01);
        }

        .table-custom {
          width: 100%;
          border-collapse: collapse;
        }

        .table-custom thead th {
          padding: 16px 20px;
          text-align: left;
          font-family: 'Inter', sans-serif;
          font-size: 0.7rem;
          font-weight: 600;
          text-transform: uppercase;
          letter-spacing: 0.5px;
          color: rgba(255,255,255,0.2);
          border-bottom: 1px solid rgba(255,255,255,0.04);
        }

        .table-custom tbody td {
          padding: 16px 20px;
          border-bottom: 1px solid rgba(255,255,255,0.03);
          font-size: 0.85rem;
          color: rgba(255,255,255,0.7);
          vertical-align: middle;
        }

        .table-custom tbody tr:last-child td {
          border-bottom: none;
        }

        .table-custom tbody tr:hover {
          background: rgba(255,255,255,0.02);
        }

        .table-custom .project-name {
          font-weight: 600;
          color: #F5F5F5;
        }

        .tech-badge-admin {
          display: inline-block;
          padding: 3px 10px;
          border-radius: 100px;
          background: rgba(255,255,255,0.03);
          border: 1px solid rgba(255,255,255,0.04);
          font-size: 0.7rem;
          color: rgba(255,255,255,0.4);
          margin: 2px 4px 2px 0;
        }

        .project-thumb {
          width: 48px;
          height: 36px;
          object-fit: cover;
          border-radius: 8px;
          border: 1px solid rgba(255,255,255,0.04);
          background: rgba(255,255,255,0.02);
        }

        .action-buttons {
          display: flex;
          gap: 6px;
          flex-wrap: wrap;
        }

        .btn-edit-admin {
          display: inline-flex;
          align-items: center;
          gap: 4px;
          padding: 6px 14px;
          border-radius: 100px;
          background: rgba(255,255,255,0.03);
          border: 1px solid rgba(255,255,255,0.04);
          color: rgba(255,255,255,0.4);
          font-size: 0.75rem;
          font-weight: 500;
          text-decoration: none;
          transition: all 0.3s ease;
        }

        .btn-edit-admin:hover {
          background: rgba(255,255,255,0.06);
          color: #F5F5F5;
        }

        .btn-delete-admin {
          display: inline-flex;
          align-items: center;
          gap: 4px;
          padding: 6px 14px;
          border-radius: 100px;
          background: rgba(255,62,165,0.04);
          border: 1px solid rgba(255,62,165,0.04);
          color: rgba(255,62,165,0.4);
          font-size: 0.75rem;
          font-weight: 500;
          cursor: pointer;
          transition: all 0.3s ease;
        }

        .btn-delete-admin:hover {
          background: rgba(255,62,165,0.1);
          border-color: rgba(255,62,165,0.1);
          color: #FF7CC7;
        }

        .empty-state-admin {
          padding: 60px 20px;
          text-align: center;
        }

        .empty-state-admin i {
          font-size: 3rem;
          color: rgba(255,255,255,0.04);
        }

        .empty-state-admin h5 {
          font-family: 'Space Grotesk', sans-serif;
          font-weight: 600;
          color: rgba(255,255,255,0.15);
          margin-top: 12px;
        }

        .empty-state-admin p {
          color: rgba(255,255,255,0.1);
          font-size: 0.85rem;
        }

        /* Mobile */
        @media (max-width: 768px) {
          .admin-sidebar {
            position: fixed;
            left: 0;
            top: 0;
            z-index: 99;
            width: 280px;
            transform: translateX(-100%);
            transition: transform 0.3s ease;
          }

          .admin-sidebar.mobile-open {
            transform: translateX(0);
          }

          .admin-sidebar.collapsed {
            transform: translateX(-100%);
          }

          .admin-main {
            padding: 20px;
            max-width: 100%;
          }

          .admin-main.expanded {
            max-width: 100%;
          }

          .sidebar-toggle {
            display: flex;
            align-items: center;
            justify-content: center;
          }

          .table-container {
            overflow-x: auto;
          }

          .table-custom {
            min-width: 600px;
          }
        }

        @media (max-width: 576px) {
          .admin-main { padding: 16px; }
          .admin-title { font-size: 1.4rem; }
          .btn-primary-admin { padding: 10px 18px; font-size: 0.75rem; }
        }
      `}</style>
      <link rel="stylesheet" href="https://cdn.jsdelivr.net/npm/bootstrap@5.3.0/dist/css/bootstrap.min.css" />
      <link rel="stylesheet" href="https://cdnjs.cloudflare.com/ajax/libs/font-awesome/6.7.2/css/all.min.css" />

      <div className="admin-layout">
        {/* Sidebar */}
        <div className={`admin-sidebar ${isSidebarOpen ? '' : 'collapsed'}`}>
          <div className="sidebar-brand">
            <span className="highlight">✦</span> Admin
          </div>
          <nav className="sidebar-nav">
            <Link to="/admin" className="nav-item active">
              <i className="fas fa-th"></i> Projects
            </Link>
            <Link to="/tambah" className="nav-item">
              <i className="fas fa-plus"></i> Add Project
            </Link>
            <Link to="/" className="nav-item">
              <i className="fas fa-arrow-left"></i> Back to Site
            </Link>
          </nav>
        </div>

        {/* Main */}
        <div className={`admin-main ${isSidebarOpen ? '' : 'expanded'}`}>
          <div className="admin-header">
            <div>
              <h1 className="admin-title">
                <span className="highlight">Projects</span>
              </h1>
              <span className="admin-badge">
                <i className="fas fa-circle" style={{ fontSize: '6px' }}></i>
                {projects.length} total
              </span>
            </div>
            <Link to="/tambah" className="btn-primary-admin">
              <i className="fas fa-plus"></i> Add Project
            </Link>
          </div>

          <AnimatePresence>
            {alertMsg && (
              <motion.div
                initial={{ opacity: 0, y: -10 }}
                animate={{ opacity: 1, y: 0 }}
                exit={{ opacity: 0, y: -10 }}
                className="alert-glass"
              >
                <div className="alert-content">
                  <i className="fas fa-check-circle"></i>
                  {alertMsg}
                </div>
                <button className="alert-close" onClick={() => setAlertMsg('')}>&times;</button>
              </motion.div>
            )}
          </AnimatePresence>

          <div className="table-container">
            <table className="table-custom">
              <thead>
                <tr>
                  <th>#</th>
                  <th>Project</th>
                  <th>Technologies</th>
                  <th>Image</th>
                  <th>Actions</th>
                </tr>
              </thead>
              <tbody>
                {projects.length > 0 ? projects.map((project, i) => (
                  <tr key={project.id}>
                    <td style={{ fontFamily: "'IBM Plex Mono', monospace", color: 'rgba(255,255,255,0.2)' }}>
                      #{String(i + 1).padStart(2, '0')}
                    </td>
                    <td className="project-name">{project.nama_project}</td>
                    <td>
                      {project.teknologi
                        ? project.teknologi.split(', ').slice(0, 2).map((t, j) => (
                          <span className="tech-badge-admin" key={j}>{t}</span>
                        ))
                        : <span style={{ color: 'rgba(255,255,255,0.15)', fontSize: '0.75rem' }}>—</span>
                      }
                      {project.teknologi && project.teknologi.split(', ').length > 2 && (
                        <span className="tech-badge-admin">+{project.teknologi.split(', ').length - 2}</span>
                      )}
                    </td>
                    <td>
                      {project.gambar
                        ? <img src={`/uploads/${project.gambar}`} className="project-thumb" alt={project.nama_project} />
                        : <span style={{ color: 'rgba(255,255,255,0.15)', fontSize: '0.75rem' }}>—</span>
                      }
                    </td>
                    <td>
                      <div className="action-buttons">
                        <Link to={`/edit/${project.id}`} className="btn-edit-admin">
                          <i className="fas fa-edit"></i> Edit
                        </Link>
                        <button className="btn-delete-admin" onClick={() => handleHapus(project.id)}>
                          <i className="fas fa-trash"></i> Delete
                        </button>
                      </div>
                    </td>
                  </tr>
                )) : (
                  <tr>
                    <td colSpan="5">
                      <div className="empty-state-admin">
                        <i className="fas fa-inbox"></i>
                        <h5>No projects yet</h5>
                        <p>Add your first project</p>
                      </div>
                    </td>
                  </tr>
                )}
              </tbody>
            </table>
          </div>
        </div>
      </div>

      <button className="sidebar-toggle" onClick={() => setIsSidebarOpen(!isSidebarOpen)}>
        <i className={`fas ${isSidebarOpen ? 'fa-chevron-left' : 'fa-chevron-right'}`}></i>
      </button>
    </>
  );
}
